// src/components/About.jsx
import { useState } from 'react';
import { personal } from '../data/portfolio';

export default function About() {
  const { bio, contact } = personal;
  const [hovered, setHovered] = useState(null);

  return (
    <section id="about" style={s.section}>
      <div style={s.inner}>

        <div className="reveal">
          <p style={s.label}>About me / Sobre mí</p>
          <h2 style={s.title}>Who I am</h2>
          <p style={s.sub}>Desarrollador con mentalidad de producto, no solo de código.</p>
        </div>

        <div style={s.layout}>

          {/* ── Columna izquierda: bio + contacto ── */}
          <div>
            {bio.map((p, i) => (
              <p key={i} className={`reveal reveal-delay-${i + 1}`} style={s.bioPara}>
                {p}
              </p>
            ))}

            <div className="reveal" style={s.infoList}>
              {[
                { label: 'Ubicación', val: contact.location },
                { label: 'Email',     val: contact.email,  href: `mailto:${contact.email}` },
                { label: 'LinkedIn',  val: 'rubén-marco',  href: contact.linkedin },
                { label: 'Idiomas',   val: contact.languages },
                { label: 'Otros',     val: contact.extras },
              ].map((item) => (
                <div key={item.label} style={s.infoItem}>
                  <span style={s.infoLabel}>{item.label}</span>
                  {item.href ? (
                    <a href={item.href} target="_blank" rel="noreferrer" style={s.infoLink}>
                      {item.val}
                    </a>
                  ) : (
                    <span style={s.infoVal}>{item.val}</span>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* ── Columna derecha: cards ── */}
          <div style={s.cardsGrid}>

            {/* Card 1 — número de fondo gigante */}
            <div
              className="reveal reveal-delay-1"
              style={{
                ...s.card1,
                borderColor: hovered === 0 ? 'rgba(232,58,58,0.5)' : 'rgba(232,58,58,0.18)',
              }}
              onMouseEnter={() => setHovered(0)}
              onMouseLeave={() => setHovered(null)}
            >
              <span style={s.card1Num} aria-hidden="true">01</span>
              <p style={s.cardTag}>Frontend</p>
              <div style={s.card1Title}>Las interfaces<br />son mi idioma</div>
              <p style={s.cardText}>
                React en producción, componentes que escalan y UIs que no necesitan explicación.
                Si el usuario lo tiene que pensar, hay algo que mejorar.
              </p>
            </div>

            {/* Card 2 — borde superior rojo */}
            <div
              className="reveal reveal-delay-2"
              style={{
                ...s.card2,
                background: hovered === 1 ? 'rgba(232,58,58,0.04)' : 'var(--card)',
              }}
              onMouseEnter={() => setHovered(1)}
              onMouseLeave={() => setHovered(null)}
            >
              <span style={s.card2Icon}>⚙️</span>
              <div style={s.card2Title}>Backend con criterio</div>
              <p style={s.cardText}>
                .NET no es solo hacer que funcione — es entender por qué funciona.
                Lógica de negocio real en una empresa real desde el primer día.
              </p>
            </div>

            {/* Card 3 — full width, SQL grande a la izquierda */}
            <div
              className="reveal reveal-delay-3"
              style={{
                ...s.card3,
                borderColor: hovered === 2 ? 'rgba(232,58,58,0.25)' : 'rgba(255,255,255,0.07)',
              }}
              onMouseEnter={() => setHovered(2)}
              onMouseLeave={() => setHovered(null)}
            >
              <div style={s.card3Left}>
                <p style={s.card3SmLabel}>Entorno real</p>
                <div style={s.card3Big}>SQL</div>
              </div>
              <div style={s.card3Divider} />
              <div>
                <div style={s.card3Title}>Los datos no mienten,<br />las queries sí</div>
                <p style={s.cardText}>
                  SQL Server en producción me enseñó más que cualquier tutorial.
                  Diseño consultas pensando en rendimiento y en el que las va a mantener después.
                </p>
              </div>
            </div>

            {/* Card 4 — quote style, full width */}
            <div
              className="reveal reveal-delay-4"
              style={{
                ...s.card4,
                background: hovered === 3 ? 'rgba(232,58,58,0.09)' : 'rgba(232,58,58,0.05)',
              }}
              onMouseEnter={() => setHovered(3)}
              onMouseLeave={() => setHovered(null)}
            >
              <div style={s.card4Quote} aria-hidden="true">"</div>
              <p style={s.card4Text}>
                No busco la zona de confort. Cada proyecto — Power BI, Qlik, Angular, Git —
                es una capa más en el stack. El techo lo pongo yo.
              </p>
              <span style={s.card4Badge}>Siempre en modo aprendizaje</span>
            </div>

          </div>
        </div>
      </div>
    </section>
  );
}

const s = {
  section:  { background: 'var(--bg2)', padding: '100px 5%' },
  inner:    { maxWidth: 1200, margin: '0 auto' },
  label:    { fontSize: 11, fontWeight: 600, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--accent)', marginBottom: 10 },
  title:    { fontFamily: 'var(--font-head)', fontSize: 'clamp(30px, 5vw, 50px)', fontWeight: 800, letterSpacing: '-2px', color: 'var(--text)', marginBottom: 8 },
  sub:      { fontSize: 15, color: 'var(--text3)', fontWeight: 300, marginBottom: 56 },
  layout:   { display: 'grid', gridTemplateColumns: '1fr 1.2fr', gap: 72, alignItems: 'start' },

  bioPara:  { fontSize: 15, color: 'var(--text2)', lineHeight: 1.82, marginBottom: 18, fontWeight: 300 },
  infoList: { display: 'flex', flexDirection: 'column', gap: 10, marginTop: 32, paddingTop: 28, borderTop: '1px solid var(--border)' },
  infoItem: { display: 'flex', gap: 14, alignItems: 'baseline' },
  infoLabel:{ fontSize: 11, letterSpacing: '0.08em', textTransform: 'uppercase', color: 'var(--text3)', minWidth: 76 },
  infoVal:  { fontSize: 14, color: 'var(--text)' },
  infoLink: { fontSize: 14, color: 'var(--accent2)', textDecoration: 'none' },

  cardsGrid:{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 },

  // Card 1
  card1: {
    background: 'var(--bg)',
    border: '1px solid rgba(232,58,58,0.18)',
    borderRadius: 14, padding: '24px 22px',
    position: 'relative', overflow: 'hidden',
    transition: 'border-color 0.22s',
    cursor: 'default',
  },
  card1Num: {
    position: 'absolute', right: 10, top: -6,
    fontFamily: 'var(--font-head)',
    fontSize: 96, fontWeight: 800,
